CREATE OR REPLACE VIEW V_DESCARGOBODEGA AS 
SELECT 'D' CLASE, MOVIMIENTO."COMPANIA",MOVIMIENTO."TIPOMOVIMIENTO",MOVIMIENTO."NUMERO",MOVIMIENTO."TERCERO",MOVIMIENTO."SUCURSAL",MOVIMIENTO."CONCEPTO",MOVIMIENTO."FECHA",MOVIMIENTO."RESPONSABLE_ORIGEN",MOVIMIENTO."SUCURSAL_RESORIGEN",MOVIMIENTO."RESPONSABLE_DESTINO",MOVIMIENTO."SUCURSAL_RESDESTINO",MOVIMIENTO."BODEGA_ORIGEN",MOVIMIENTO."BODEGA_DESTINO",MOVIMIENTO."HORA",MOVIMIENTO."DESCRIPCION",MOVIMIENTO."PORCIVAGLOBAL",MOVIMIENTO."TIPOMOVASOCIADO",MOVIMIENTO."MOVASOCIADO",MOVIMIENTO."FECHAMOVASOCIADO",MOVIMIENTO."VALORIVA",MOVIMIENTO."VALORDESCUENTO",MOVIMIENTO."VALORTOTAL",MOVIMIENTO."VACIA",MOVIMIENTO."CENTRODECOSTO",MOVIMIENTO."REMISIONNO",MOVIMIENTO."FACTURANO",MOVIMIENTO."VALORDOCASOCIADO",MOVIMIENTO."AJUSTECENTAVOS",MOVIMIENTO."AJUSTECENTAVOS1",MOVIMIENTO."REGISTRADO",MOVIMIENTO."IMPRESO",MOVIMIENTO."GENERADO",MOVIMIENTO."AUXILIAR",MOVIMIENTO."TOTALCONAJUSTE",MOVIMIENTO."PROVEEDORCA",MOVIMIENTO."SUCURSALCA",MOVIMIENTO."VALORTOTALCONIVA",MOVIMIENTO."FINICIO_CONTRATO",MOVIMIENTO."FFINAL_CONTRATO",MOVIMIENTO."AJUSTE_DEC_MANUAL",MOVIMIENTO."CREATED_BY",MOVIMIENTO."DATE_CREATED",MOVIMIENTO."MODIFIED_BY",MOVIMIENTO."DATE_MODIFIED",MOVIMIENTO."CLASE_BODEGA_ORIGEN",MOVIMIENTO."CLASE_BODEGA_DESTINO",MOVIMIENTO."DEPENDENCIA_ORIGEN",MOVIMIENTO."DEPENDENCIA_DESTINO"
FROM MOVIMIENTO
WHERE (CLASE_BODEGA_ORIGEN IN(40,50) AND CLASE_BODEGA_DESTINO IN(60))
